-- Settleable predictions: generalize recurrence occurrences into a single
-- predictions ledger (financial_predictions).
--
-- A prediction is a future financial commitment/expectation. It can be
-- standalone (recurrence_id null) or generated by a recurrence. Each row is
-- a snapshot (description/type/category/expected account) so editing or
-- deleting the recurrence never rewrites history. Settling a prediction
-- creates the real transaction with the real account/date/amount.

-- ============================================================
-- 1) Rename table and settlement link column
-- ============================================================

alter table if exists public.transaction_recurrence_occurrences
  rename to financial_predictions;

alter table public.financial_predictions
  rename column source_transaction_id to settled_transaction_id;

-- ============================================================
-- 2) Identity/snapshot columns for standalone predictions
-- ============================================================

alter table public.financial_predictions
  add column if not exists owner_user_id uuid references auth.users (id) on delete cascade,
  add column if not exists family_id uuid references public.families (id) on delete set null,
  add column if not exists account_id uuid references public.accounts (id) on delete set null,
  add column if not exists category_id uuid references public.categories (id) on delete set null,
  add column if not exists type text,
  add column if not exists description text,
  add column if not exists settled_date date,
  add column if not exists settled_amount numeric(12, 2);

-- Backfill existing recurrence occurrences from their parent recurrence
update public.financial_predictions p
set
  owner_user_id = r.owner_user_id,
  family_id = r.family_id,
  account_id = r.account_id,
  category_id = r.category_id,
  type = r.type,
  description = r.description
from public.transaction_recurrences r
where r.id = p.recurrence_id
  and p.owner_user_id is null;

-- ============================================================
-- 3) Status values: confirmed -> settled, skipped -> canceled
-- ============================================================

alter table public.financial_predictions
  drop constraint if exists transaction_recurrence_occurrences_status_check;

update public.financial_predictions set status = 'settled' where status = 'confirmed';
update public.financial_predictions set status = 'canceled' where status = 'skipped';

alter table public.financial_predictions
  add constraint financial_predictions_status_check
  check (status in ('predicted', 'settled', 'canceled'));

-- ============================================================
-- 4) Structural constraints
-- ============================================================

alter table public.financial_predictions
  alter column recurrence_id drop not null,
  alter column owner_user_id set not null,
  alter column type set not null,
  alter column description set not null;

-- Standalone predictions are expense/income only; legacy transfer
-- occurrences generated by recurrences remain valid but cannot be settled.
alter table public.financial_predictions
  drop constraint if exists financial_predictions_type_check;

alter table public.financial_predictions
  add constraint financial_predictions_type_check check (
    type in ('expense', 'income')
    or (recurrence_id is not null and type = 'transfer')
  );

-- Settlement data only exists on settled rows
alter table public.financial_predictions
  drop constraint if exists recurrence_occurrences_source_check;

alter table public.financial_predictions
  add constraint financial_predictions_settlement_check check (
    status = 'settled'
    or (
      settled_transaction_id is null
      and settled_date is null
      and settled_amount is null
    )
  );

-- ============================================================
-- 5) Indexes
-- ============================================================

alter index if exists recurrence_occurrences_unique_date
  rename to financial_predictions_unique_recurrence_date;

alter index if exists recurrence_occurrences_unique_source
  rename to financial_predictions_unique_settled_transaction;

alter index if exists idx_recurrence_occurrences_scheduled_date
  rename to idx_financial_predictions_scheduled_date;

alter index if exists idx_recurrence_occurrences_status
  rename to idx_financial_predictions_status;

create index if not exists idx_financial_predictions_owner_user_id
  on public.financial_predictions (owner_user_id);

create index if not exists idx_financial_predictions_family_id
  on public.financial_predictions (family_id)
  where family_id is not null;

create index if not exists idx_financial_predictions_account_id
  on public.financial_predictions (account_id)
  where account_id is not null;

-- ============================================================
-- 6) RLS: owner/family based (predictions have their own identity now)
-- ============================================================

drop policy if exists recurrence_occurrences_select on public.financial_predictions;
drop policy if exists recurrence_occurrences_insert on public.financial_predictions;
drop policy if exists recurrence_occurrences_update on public.financial_predictions;
drop policy if exists recurrence_occurrences_delete on public.financial_predictions;

drop policy if exists financial_predictions_select on public.financial_predictions;
create policy financial_predictions_select on public.financial_predictions
  for select to authenticated
  using (
    owner_user_id = auth.uid()
    or (
      family_id is not null
      and public.is_family_member(family_id, auth.uid())
    )
  );

drop policy if exists financial_predictions_insert on public.financial_predictions;
create policy financial_predictions_insert on public.financial_predictions
  for insert to authenticated
  with check (
    owner_user_id = auth.uid()
    and (
      family_id is null
      or public.is_family_member(family_id, auth.uid())
    )
  );

drop policy if exists financial_predictions_update on public.financial_predictions;
create policy financial_predictions_update on public.financial_predictions
  for update to authenticated
  using (
    owner_user_id = auth.uid()
    or (
      family_id is not null
      and public.is_family_member(family_id, auth.uid())
    )
  )
  with check (
    owner_user_id = auth.uid()
    or (
      family_id is not null
      and public.is_family_member(family_id, auth.uid())
    )
  );

drop policy if exists financial_predictions_delete on public.financial_predictions;
create policy financial_predictions_delete on public.financial_predictions
  for delete to authenticated
  using (
    owner_user_id = auth.uid()
    or (
      family_id is not null
      and public.is_family_admin(family_id, auth.uid())
    )
  );

-- ============================================================
-- 7) Settlement: atomic function (transaction + balance + link)
-- ============================================================

create or replace function public.settle_financial_prediction(
  p_prediction_id uuid,
  p_account_id uuid,
  p_settled_date date,
  p_amount numeric default null
)
returns uuid
language plpgsql
security definer
set search_path = public
as $$
declare
  v_prediction public.financial_predictions%rowtype;
  v_amount numeric(12, 2);
  v_family_id uuid;
  v_transaction_id uuid;
begin
  select *
  into v_prediction
  from public.financial_predictions
  where id = p_prediction_id
  for update;

  if not found then
    raise exception 'Prediction not found';
  end if;

  if v_prediction.status <> 'predicted' then
    raise exception 'Only predicted entries can be settled';
  end if;

  if v_prediction.type not in ('expense', 'income') then
    raise exception 'Only expense or income predictions can be settled';
  end if;

  if not (
    v_prediction.owner_user_id = auth.uid()
    or (
      v_prediction.family_id is not null
      and public.is_family_member(v_prediction.family_id, auth.uid())
    )
  ) then
    raise exception 'Not allowed to settle this prediction'
      using errcode = '42501';
  end if;

  if not public.can_post_to_account(p_account_id, auth.uid()) then
    raise exception 'Not allowed to post to this account'
      using errcode = '42501';
  end if;

  v_amount := coalesce(p_amount, v_prediction.amount);

  if v_amount is null or v_amount <= 0 then
    raise exception 'Invalid settlement amount';
  end if;

  select a.family_id into v_family_id
  from public.accounts a
  where a.id = p_account_id;

  insert into public.transactions (
    description,
    amount,
    type,
    category_id,
    account_id,
    transaction_date,
    created_by,
    family_id
  )
  values (
    v_prediction.description,
    v_amount,
    v_prediction.type,
    v_prediction.category_id,
    p_account_id,
    p_settled_date,
    auth.uid(),
    v_family_id
  )
  returning id into v_transaction_id;

  update public.accounts
  set balance = balance + case
    when v_prediction.type = 'income' then v_amount
    else -v_amount
  end
  where id = p_account_id;

  update public.financial_predictions
  set
    status = 'settled',
    settled_transaction_id = v_transaction_id,
    settled_date = p_settled_date,
    settled_amount = v_amount
  where id = p_prediction_id;

  return v_transaction_id;
end;
$$;

revoke all on function public.settle_financial_prediction(uuid, uuid, date, numeric) from public;
grant execute on function public.settle_financial_prediction(uuid, uuid, date, numeric) to authenticated;

-- Superseded by settle_financial_prediction
drop function if exists public.confirm_recurrence_occurrence(uuid);
